import "mx-global";
import { Big } from "big.js";

// BEGIN EXTRA CODE
// END EXTRA CODE

/**
 * This is a modal that will show until the specified amount of time has passed.
 * 
 * Ideal for calling a potentially long running RESTful API in a nanoflow after this JavaScript action. Then handle the HTTP response as needed.
 * @param {string} title
 * @param {string} message
 * @param {Big} duration - Milliseconds
 * @returns {Promise.<void>}
 */
export async function JS_Modal_Countdown(title, message, duration) {
	// BEGIN USER CODE
	let timerInterval;
	Swal.fire({
		title: title,
		html: message + '<br /><br /><p>This modal will time out in <b></b> seconds.</p>',
		icon: 'info',
		showConfirmButton: false,
		showCancelButton: false,
		showCloseButton: false,
		allowOutsideClick: false,
		position: 'center',
		timer: duration,
		timerProgressBar: true,
		didOpen: (e) => {
			const b = Swal.getHtmlContainer().querySelector('b');
			timerInterval = setInterval(() => {
				b.textContent = Math.round(Swal.getTimerLeft() / 1000)
			}, 100);
		},
		willClose: (e) => {
			clearInterval(timerInterval);
		}
	}).then((result) => {
		if (result.dismiss === Swal.DismissReason.timer) {
			Swal.fire({
				icon: 'info',
				title: 'Timer Expired',
				html: 'This modal was closed by the timer.',
				position: 'center',
				showCloseButton: true,
				showCancelButton: true,
				cancelButtonText: 'Close'
			});
		} else
		{
			Swal.fire({
				icon: 'error',
				title: 'Something Went Wrong',
				html: 'A different issue occurred.',
				position: 'center',
				showCloseButton: true,
				showCancelButton: true,
				cancelButtonText: 'Close'
			});
		}
	});
	// END USER CODE
}
